"""Test Python with verbose output to see all iterations."""

import numpy as np
import pandas as pd
import sys
sys.path.insert(0, 'omnilss/src')

from omnilss.algorithms import rs_fit

# Load data generated by R
df = pd.read_csv("scripts/diagnostic/test_data_nbi.csv")
y = df['y'].values
x1 = df['x1'].values

data = {
    'y': y,
    'x1': x1
}

print("=" * 70)
print("Python RS Algorithm with Verbose Output")
print("=" * 70)

# Fit model with RS algorithm and verbose output
model = rs_fit(
    formula="y ~ x1",
    sigma_formula="~1",
    family="NBI",
    data=data,
    max_iter=20,
    tol=1e-4,
    verbose=True
)

print("\n" + "=" * 70)
print("Final Results:")
print("=" * 70)
print(f"Global Deviance: {model.g_dev:.6f}")
print(f"Mu coefficients: {model.coefficients['mu']}")
print(f"Sigma: {np.exp(model.coefficients['sigma'][0]):.6f}")
print("=" * 70)
